quickstart:
npm i @gravity-ui/date-utils

import {dateTimeParse, dateTime} from '@gravity-ui/date-utils';

// parse absolute date
dateTimeParse('2021-08-07')?.format('YYYY-MM-DDTHH:mm:ssZ');
// parse relative date
dateTimeParse('now-1d')?.format('YYYY-MM-DDTHH:mm:ssZ');
// create dateTime
dateTime({input: '2021-08-07', timeZone: 'Europe/Istanbul'}).format('YYYY-MM-DDTHH:mm:ssZ');
// manage settings
import {settings} from '@gravity-ui/date-utils';
settings.loadLocale('de').then(() => settings.setLocale('de'));
